#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeSessionOrchestrator: FfiConverter {
    typealias FfiType = UInt64
    typealias SwiftType = SessionOrchestrator

    public static func lift(_ handle: UInt64) throws -> SessionOrchestrator {
        return SessionOrchestrator(unsafeFromHandle: handle)
    }

    public static func lower(_ value: SessionOrchestrator) -> UInt64 {
        return value.uniffiCloneHandle()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> SessionOrchestrator {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: SessionOrchestrator, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeSessionOrchestrator_lift(_ handle: UInt64) throws -> SessionOrchestrator {
    return try FfiConverterTypeSessionOrchestrator.lift(handle)
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeSessionOrchestrator_lower(_ value: SessionOrchestrator) -> UInt64 {
    return FfiConverterTypeSessionOrchestrator.lower(value)
}




/**
 * 1文字分の表示属性。`start`/`length`は`text`のUTF-16コードユニットオフセット。
 */
public struct AttributeRun: Equatable, Hashable {
    public var start: UInt32
    public var length: UInt32
    public var fgArgb: UInt32
    public var bgArgb: UInt32
    public var bold: Bool
    public var underline: Bool

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(start: UInt32, length: UInt32, fgArgb: UInt32, bgArgb: UInt32, bold: Bool, underline: Bool) {
        self.start = start
        self.length = length
        self.fgArgb = fgArgb
        self.bgArgb = bgArgb
        self.bold = bold
        self.underline = underline
    }

    

    
}

#if compiler(>=6)
extension AttributeRun: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeAttributeRun: FfiConverterRustBuffer {
    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> AttributeRun {
        return
            try AttributeRun(
                start: FfiConverterUInt32.read(from: &buf), 
                length: FfiConverterUInt32.read(from: &buf), 
                fgArgb: FfiConverterUInt32.read(from: &buf), 
                bgArgb: FfiConverterUInt32.read(from: &buf), 
                bold: FfiConverterBool.read(from: &buf), 
                underline: FfiConverterBool.read(from: &buf)
