        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .plainSsh
        
        case 2: return .tsshdQuic
        
        case 3: return .isekaiPipeQuic
        
        case 4: return .auto
        
        case 5: return .isekaiPipeQuicMultipath
        
        case 6: return .isekaiStunP2pQuic
        
